class Alarm {
    private AlarmSeverity severity;
    private AlarmOwner owner;
    private AlarmStatus status;
    private final NotificationDispatcher notificationDispatcher;

    Alarm(AlarmSeverity severity, NotificationDispatcher notificationDispatcher) {
        this.severity = severity;
        this.notificationDispatcher = notificationDispatcher;
        this.status = AlarmStatus.NEW;
    }

    void markAsUnownedCritical() {
        this.status = AlarmStatus.UNOWNED_CRITICAL;
        if (severity == AlarmSeverity.HIGH) {
            notificationDispatcher.notifyAllHandlers(this);
        }
    }
}
